actions.action:

def myTransaction = transaction(
	event: {
		createCase("transaction_test", "onButton")
		change text_without_action value { "xxx" }
	},
	onCommit: { createCase("transaction_test", "onCommit") },
	onRollBack: { createCase("transaction_test", "onRollBack") }
)
createCase("transaction_test", "onAlways")
change was_transaction_rolled_back value { myTransaction.wasRolledBack }


def myTransaction = transaction(
	event: {
		deleteCase(findCase({it.title.eq("toBeRemoved")}))
		createCase("transaction_test", "onButton")
		change text_without_action value { "xxx" }
		// not runtime exception on purpose
		throw new IllegalAccessException("error")
	},
	onCommit: { createCase("transaction_test", "onCommit") },
	onRollBack: { createCase("transaction_test", "onRollBack") }
)
createCase("transaction_test", "onAlways")
change was_transaction_rolled_back value { myTransaction.wasRolledBack }


transaction {
	createCase("transaction_test", "transactional create case")
}


def myTransaction = transaction(
	event: {
		petriNetService.importProcess(new com.netgrif.application.engine.petrinet.domain.params.ImportProcessParams(
				new java.io.FileInputStream("src/test/resources/petriNets/transaction/transaction_test_secondary.xml"),
				com.netgrif.application.engine.petrinet.domain.VersionType.MAJOR,
				userService.getSystemUser().stringId))
		def toBeRemovedCase = createCase("transaction_test_secondary", "toBeRemoved")
		assignTask("t1", toBeRemovedCase)
		deleteCase(toBeRemovedCase)
		createCase("transaction_test", "onButton")
		throw new RuntimeException("error")
	},
	onCommit: { createCase("transaction_test", "onCommit") },
	onRollBack: { createCase("transaction_test", "onRollBack") }
)
createCase("transaction_test", "onAlways")
change was_transaction_rolled_back value { myTransaction.wasRolledBack }


